CommonData.BannerCustomCSS:
#onetrust-banner-sdk #onetrust-policy-text a {
    margin: 0px;
}

#onetrust-consent-sdk #onetrust-banner-sdk.otFloatingRounded {
    border-radius: 6px;
}

#onetrust-banner-sdk #onetrust-policy {
    margin-top: 24px;
}

#onetrust-consent-sdk #onetrust-accept-btn-handler,
#onetrust-consent-sdk #onetrust-pc-btn-handler,
#onetrust-banner-sdk #onetrust-reject-all-handler {
    border-radius: 6px;
    text-transform: uppercase;
    letter-spacing: 1.2px;
    font-weight: 500 !important;
    padding: 0 16px;
    line-height: 36px;
    border: 1px solid #146aff !important;
}

#onetrust-banner-sdk :not(.ot-leg-btn-container)>button:not(.ot-link-btn):hover,
#onetrust-banner-sdk :not(.ot-leg-btn-container)>button:not(.ot-link-btn):focus {
    opacity: 1 !important;
}

#onetrust-consent-sdk #onetrust-accept-btn-handler:focus,
#onetrust-consent-sdk #onetrust-accept-btn-handler:hover,
#onetrust-banner-sdk #onetrust-reject-all-handler:focus,
#onetrust-banner-sdk #onetrust-reject-all-handler:hover,
#onetrust-consent-sdk #onetrust-pc-btn-handler:focus,
#onetrust-consent-sdk #onetrust-pc-btn-handler:hover {
    background-color: #e3edff !important;
}

#onetrust-banner-sdk .has-reject-all-button #onetrust-button-group {
    display: flex;
    flex-direction: row-reverse;
}

#onetrust-banner-sdk .onetrust-banner-options {
    float: none;
    max-width: 100%;
    flex-basis: 100%;
    display: flex;
    justify-content: space-between;
}

@media only screen and (max-width: 640px) {
    #onetrust-banner-sdk .has-reject-all-button #onetrust-button-group {
        flex-wrap: wrap;
    }

    #onetrust-banner-sdk .onetrust-banner-options {
        flex-wrap: wrap-reverse;
    }

    #onetrust-consent-sdk #onetrust-accept-btn-handler,
    #onetrust-banner-sdk #onetrust-reject-all-handler,
    #onetrust-consent-sdk #onetrust-pc-btn-handler {
        width: 100%;
    }

    #onetrust-banner-sdk #onetrust-reject-all-handler,
    #onetrust-consent-sdk #onetrust-pc-btn-handler {
        margin-right: 0;
    }
}

CommonData.PCCustomCSS:
#onetrust-pc-sdk {
    border-radius: 6px;
}

#onetrust-pc-sdk #accept-recommended-btn-handler,
#onetrust-pc-sdk .ot-btn-container button,
#onetrust-pc-sdk .ot-btn-container .ot-pc-refuse-all-handler {
    border-radius: 6px;
    text-transform: uppercase;
    letter-spacing: 1.2px;
    font-weight: normal;
    padding: 0 16px;
    line-height: 36px;
    font-size: .75em;
    border: 1px solid #146aff !important;
}

#onetrust-pc-sdk .ot-pc-refuse-all-handler:hover,
#onetrust-pc-sdk .ot-pc-refuse-all-handler:focus,
#onetrust-pc-sdk .onetrust-close-btn-handler:hover,
#onetrust-pc-sdk .onetrust-close-btn-handler:focus,
#onetrust-pc-sdk #accept-recommended-btn-handler:hover,
#onetrust-pc-sdk #accept-recommended-btn-handler:focus {
    background-color: #e3edff !important;
    opacity: 1 !important;
}

#onetrust-pc-sdk #ot-pc-desc a {
    margin: 0;
    color: #183444;
}
